#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""Fix the email-scaler (exit-0-safe). Root cause: atlas-deepcrawl.service has a 5min
TimeoutStartSec but crawls 30 sites x many pages x 12s timeouts -> killed before it writes.
Fix via systemd drop-ins (merge, never replace base unit): small batch + generous timeout +
frequent re-fire cadence so every run finishes and produces. Then fires one run now."""
import os,sys,json,time,subprocess
def sh(c,t=30):
    try:
        r=subprocess.run(["bash","-lc",c],capture_output=True,text=True,timeout=t);return (r.stdout+r.stderr).strip()
    except Exception as e: return "TO/ERR:%s"%e
out={"kind":"scaler_fix","ts":int(time.time())}
try:
    sd="/etc/systemd/system/atlas-deepcrawl.service.d"; td="/etc/systemd/system/atlas-deepcrawl.timer.d"
    os.makedirs(sd,exist_ok=True); os.makedirs(td,exist_ok=True)
    open(sd+"/override.conf","w").write("[Service]\nEnvironment=DEEPCRAWL_BATCH=5\nTimeoutStartSec=600\n")
    # OnUnitInactiveSec re-fires a oneshot (OnUnitActiveSec does NOT) -> run ~every 2min
    open(td+"/override.conf","w").write("[Timer]\nOnBootSec=60\nOnUnitInactiveSec=120\n")
    out["service_override"]=open(sd+"/override.conf").read()
    out["timer_override"]=open(td+"/override.conf").read()
    out["daemon_reload"]=sh("systemctl daemon-reload 2>&1; echo rc=$?")
    out["timer_enable"]=sh("systemctl enable --now atlas-deepcrawl.timer 2>&1; systemctl is-active atlas-deepcrawl.timer")
    out["kick"]=sh("systemctl restart --no-block atlas-deepcrawl.service 2>&1; echo started")
    out["effective_batch"]=sh("systemctl show atlas-deepcrawl.service -p Environment -p TimeoutStartUSec 2>&1")
except Exception as e:
    out["error"]=str(e)
def envf(p):
    d={}
    try:
        for ln in open(p):
            ln=ln.strip()
            if ln.startswith('export '): ln=ln[7:]
            if '=' in ln and not ln.startswith('#'):
                k,v=ln.split('=',1); d[k.strip()]=v.strip().strip('"').strip("'")
    except Exception: pass
    return d
try:
    import base64,urllib.request,urllib.error
    env=envf("/etc/atlas/autopull.env")
    tok=env.get("STATUS_TOKEN") or os.environ.get("STATUS_TOKEN"); repo=env.get("STATUS_REPO") or "cloudwalker171/atlas-manifests"
    br="main"; api="https://api.github.com"; path="status/hetzner/scaler-fix.json"
    if tok and repo:
        url="%s/repos/%s/contents/%s"%(api,repo,path); sha=None
        try:
            r=urllib.request.Request(url+"?ref="+br,headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); sha=json.load(urllib.request.urlopen(r,timeout=20)).get("sha")
        except Exception: sha=None
        body={"message":"scaler_fix","content":base64.b64encode(json.dumps(out,indent=2,default=str).encode()).decode(),"branch":br}
        if sha: body["sha"]=sha
        for _ in range(4):
            try:
                rq=urllib.request.Request(url,data=json.dumps(body).encode(),method="PUT",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas","Content-Type":"application/json"}); urllib.request.urlopen(rq,timeout=25); break
            except urllib.error.HTTPError as e:
                if e.code==409:
                    try:
                        rq2=urllib.request.Request(url+"?ref="+br,headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); body["sha"]=json.load(urllib.request.urlopen(rq2,timeout=20)).get("sha")
                    except Exception: pass
                else: break
            except Exception: time.sleep(2)
except Exception: pass
sys.exit(0)
